+// btrfs-progs computes command CRC32C over the command header with the CRC
+// field zeroed plus the payload bytes (`common/send-stream.c`).
+fn btrfs_send_crc32c(seed: u32, data: &[u8]) -> u32 {
+    let mut crc = seed;
+    for byte in data {
+        crc ^= u32::from(*byte);
+        for _ in 0..8 {
+            crc = if crc & 1 == 0 {
+                crc >> 1
+            } else {
+                (crc >> 1) ^ BTRFS_SEND_CRC32C_POLY
+            };
+        }
+    }
+    crc
+}
